import React from "react";
import { useNavigate } from "react-router-dom";

const Checkout = () => {
  const navigate = useNavigate();

  const handlePlaceOrder = (e) => {
    e.preventDefault();
    // here you call backend to create order
    navigate("/thank-you");
  };

  return (
    <div style={{ padding: "36px 10%" }}>
      <h2>Thanh toán</h2>
      <form onSubmit={handlePlaceOrder} style={{ maxWidth: 700 }}>
        <div style={{ marginBottom: 12 }}>
          <label>Họ tên</label>
          <input required style={{ width: "100%", padding: 8 }} />
        </div>
        <div style={{ marginBottom: 12 }}>
          <label>Địa chỉ</label>
          <input required style={{ width: "100%", padding: 8 }} />
        </div>
        <div style={{ marginBottom: 12 }}>
          <label>Thanh toán</label>
          <select style={{ width: "100%", padding: 8 }}>
            <option>Thanh toán khi nhận hàng</option>
            <option>Chuyển khoản</option>
          </select>
        </div>
        <button className="btn" type="submit">Đặt hàng</button>
      </form>
    </div>
  );
};

export default Checkout;
